INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4f5c4644-8310-4755-a38a-f68889bdc6b3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin ‚Äî Choosing the Right Data Storage for Android Apps$escape$,
  $escape$When it comes to data persistence in Kotlin for Android, you have multiple options: Room, DataStore, SharedPreferences, and file storage. Room is an ORM that provides a simple, SQL-based interface for database operations. DataStore, on the other hand, is a more recent addition, providing an abstraction layer for shared preferences and other data storage solutions. SharedPreferences and file storage are simple, but less scalable options. To choose the right one, consider the complexity of your data model and the frequency of updates.$escape$,
  $escape$val db = Room.databaseBuilder(
    context, MyDatabase::class.java, "my-db")
        .build()$escape$,
  $escape$kotlin$escape$,
