INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'da8cfa85-2184-4868-8979-6a7e9f2ad22b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin Android App Architecture: MVVM vs MVI vs Clean Architecture$escape$,
  $escape$In Kotlin Android development, choosing the right architecture is crucial for scalability and maintainability. MVVM (Model-View-ViewModel) is a popular choice, leveraging data binding and live data. MVI (Model-View-Intent) is another option, focusing on unidirectional data flow. Clean Architecture, inspired by Robert C. Martin, separates the business logic from the presentation layer. Use cases, such as `GetUserUseCase`, encapsulate the business logic. Kotlin Coroutines facilitate asynchronous programming.$escape$,
  $escape$class GetUserUseCase(private val repository: UserRepository) {
   suspend fun execute(): User {
       return repository.getUser()
   }
}$escape$,
  $escape$kotlin$escape$,
