INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '29bebff5-8c6b-45bd-85dd-89b0e1f0c2fb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kotlin: Mastering Compose Testing with JUnit and Mockk$escape$,
  $escape$In Compose testing, you can't mock a `MutableState` directly. Instead, use a `@RunWith(MockitoJUnitRunner::class)` annotation with `@Mock` to create a mock object. Then, use `every` from Mockk to verify interactions. For UI tests, Espresso provides a robust set of assertions for testing views. To access a Compose view's state, use the `getOrNull` method. Here's an example of mocking a Compose view's state with Mockk and testing its UI with Espresso:
```kotlin
@get:Rule
val composeRule = createComposeRule()

@Mock
private lateinit var mockState: MutableState<String>

@Before
fun setup() {
    MockitoAnnotations.initMocks(this)
    mockState = mockk()
}

@Test
fun testComposeView() {
    every { mockState.getOrNull() } returns "Hello, World!"
    // Perform actions and assertions here
}

@Test
fun testUi() {
    composeRule.runOnMainSync {
        // Perform actions and assertions here
    }
    onView(withId(R.id.compose_view)).check(matches(withText("Hello, World!")))
}$escape$,
  $escape$kotlin$escape$,
  $escape$kotlin$escape$,
